def find_max(arr):
    max_val = arr[0]
    for x in arr:          # Visits every element — O(n)
        if x > max_val:
            max_val = x
    return max_val

def bubble_sort(arr):
    n = len(arr)
    for i in range(n):          # Outer loop — O(n)
        for j in range(n - 1): # Inner loop — O(n)
            if arr[j] > arr[j+1]:
                arr[j], arr[j+1] = arr[j+1], arr[j]
# Total: O(n²)

def fibonacci(n):
    if n <= 1: return n
    return fibonacci(n-1) + fibonacci(n-2)  # Two recursive calls — O(2ⁿ)

# O(n) time, O(1) space — modifies in place
def reverse_in_place(arr):
    lo, hi = 0, len(arr) - 1
    while lo < hi:
        arr[lo], arr[hi] = arr[hi], arr[lo]
        lo += 1; hi -= 1

# O(n) time, O(n) space — creates a new list
def reverse_copy(arr):
    return arr[::-1]

from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n):
    if n <= 1: return n
    return fib(n-1) + fib(n-2)
# Time: O(n) — each value computed once
# Space: O(n) — cache stores n values
